import{_ as p,C as l,o as m,c as h,j as n,a as i,E as e,a3 as s}from"./chunks/framework.CVjg771q.js";const x=JSON.parse('{"title":"阴符经","description":"一部篇幅极短、语言峻利的道家经典。","frontmatter":{"title":"阴符经","description":"一部篇幅极短、语言峻利的道家经典。","category":"guide","aliases":["阴符经","黄帝阴符经","yinfu jing","阴符"],"source":["《黄帝阴符经》"]},"headers":[],"relativePath":"daoism/starter-texts/yinfu-jing.md","filePath":"daoism/starter-texts/yinfu-jing.md","lastUpdated":1779783531000}'),d={name:"daoism/starter-texts/yinfu-jing.md"};function g(u,a,y,b,c,f){const o=l("DaoReadingPrelude"),r=l("DaoOriginalReading"),t=l("DaoKeywordCards");return m(),h("div",null,[a[0]||(a[0]=n("h1",{id:"阴符经",tabindex:"-1"},[i("阴符经 "),n("a",{class:"header-anchor",href:"#阴符经","aria-label":'Permalink to "阴符经"'},"​")],-1)),e(o,{title:"先分上中下三篇，再顺着机的脉络读",summary:"《阴符经》篇幅不长，但语势峻厉、转折密集。更适合的进入方式，是先按上、中、下三篇分别去读：上篇看天道与杀机，中篇看三盗与时机，下篇看自然之道与阴阳变化。",points:[{label:"先读",text:"先顺着三篇各读一遍，不急着逐句解释。"},{label:"再辨",text:"留意“机”怎样在天、人、万物之间反复出现。"},{label:"后想",text:"最后回到自然之道、应机而动这条总线。"}],hint:"这篇适合分篇读，不必一口气把三篇压成一团；先让每一篇各自立住，再回头看它们如何互相照应。"}),a[1]||(a[1]=n("h2",{id:"【原典层】原文",tabindex:"-1"},[i("【原典层】原文 "),n("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),a[2]||(a[2]=n("h3",{id:"上篇",tabindex:"-1"},[i("上篇 "),n("a",{class:"header-anchor",href:"#上篇","aria-label":'Permalink to "上篇"'},"​")],-1)),e(r,{chapterMark:"上篇",colophon:"观天 · 杀机 · 修炼",tone:"ink",skin:"yinfu",paragraphs:["观天之道，执天之行，尽矣。","天有五贼，见之者昌。","五贼在心，施行于天。","宇宙在乎手，万化生乎身。","天性，人也；人心，机也。","立天之道，以定人也。","天发杀机，移星易宿；","地发杀机，龙蛇起陆；","人发杀机，天地反覆。","天人合发，万变定基。","性有巧拙，可以伏藏。","九窍之邪，在乎三要，可以动静。","火生于木，祸发必克；","奸生于国，时动必溃。","知之修炼，谓之圣人。"],"aria-label":"阴符经上篇原文"}),a[3]||(a[3]=n("h3",{id:"中篇",tabindex:"-1"},[i("中篇 "),n("a",{class:"header-anchor",href:"#中篇","aria-label":'Permalink to "中篇"'},"​")],-1)),e(r,{chapterMark:"中篇",colophon:"三盗 · 时机 · 神明",tone:"ink",skin:"yinfu",paragraphs:["天生天杀，道之理也。","天地，万物之盗；","万物，人之盗；","人，万物之盗。","三盗既宜，三才既安。","故曰：食其时，百骸理；","动其机，万化安。","人知其神之神，不知不神之所以神。","日月有数，大小有定；","圣功生焉，神明出焉。","其盗机也，天下莫能见，莫能知。","君子得之固躬，小人得之轻命。"],"aria-label":"阴符经中篇原文"}),a[4]||(a[4]=n("h3",{id:"下篇",tabindex:"-1"},[i("下篇 "),n("a",{class:"header-anchor",href:"#下篇","aria-label":'Permalink to "下篇"'},"​")],-1)),e(r,{chapterMark:"下篇",colophon:"自然 · 阴阳 · 制机",tone:"ink",skin:"yinfu",paragraphs:["瞽者善听，聋者善视。","绝利一源，用师十倍。","三返昼夜，用师万倍。","心生于物，死于物，机在目。","天之无恩而大恩生，","迅雷烈风，莫不蠢然。","至乐性余，至静性廉。","天之至私，用之至公。","禽之制在气。","生者死之根，死者生之根。","恩生于害，害生于恩。","愚人以天地文理圣，","我以时物文理哲。","人以愚虞圣，我以不愚虞圣；","人以奇期圣，我以不奇期圣。","故曰：沉水入火，自取灭亡。","自然之道静，故天地万物生。","天地之道浸，故阴阳胜。","阴阳相推，而变化顺矣。","是故圣人知自然之道不可违，","因而制之。","至静之道，律历所不能契。","爰有奇器，是生万象，","八卦甲子，神机鬼藏。","阴阳相胜之术，昭昭乎进乎象矣。"],"aria-label":"阴符经下篇原文"}),a[5]||(a[5]=n("h2",{id:"【原典层】字词释义",tabindex:"-1"},[i("【原典层】字词释义 "),n("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),a[6]||(a[6]=n("h3",{id:"上篇-1",tabindex:"-1"},[i("上篇 "),n("a",{class:"header-anchor",href:"#上篇-1","aria-label":'Permalink to "上篇"'},"​")],-1)),e(t,{items:[{term:"执天之行",pinyin:["zhí","tiān","zhī","xíng"],meaning:"把握天道的运行法则并依之而行。开篇「观天之道，执天之行」观与执并举：观是看清，执是循行，二者不可偏废。"},{term:"尽",pinyin:["jìn"],meaning:"穷尽、完备。「观天之道，执天之行，尽矣」——天道与人行合一，便是全部要义，无需更多繁复名相。"},{term:"贼",pinyin:["zéi"],meaning:"非盗贼之贼，而是天地间相互制衡、相互夺取的力量。「天有五贼」即五行相克相夺之理，见之者能顺势而为。"},{term:"施行",pinyin:["shī","xíng"],meaning:"推行、作用于外。「五贼在心，施行于天」——心中明了五贼之理，再将其推行到天地之间，由内而外。"},{term:"万化",pinyin:["wàn","huà"],meaning:"万事万物的变化。「宇宙在乎手，万化生乎身」——天地变化虽繁，皆可由人身而感知、由人心而推演。"},{term:"定基",pinyin:["dìng","jī"],meaning:"沉定的根基。「天人合发，万变定基」——变化再多，只要天人合机，最终仍能落到一个新的稳固根基上。"},{term:"伏藏",pinyin:["fú","cáng"],meaning:"收敛潜藏。「性有巧拙，可以伏藏」——人无论性分巧拙，都不必急于尽发，懂得收敛、留有余地才是工夫。"},{term:"九窍",pinyin:["jiǔ","qiào"],meaning:"人身九窍（眼耳鼻口等），是感官与外物相接的门户。窍开则心易被牵，守窍之要在于知动静。"},{term:"邪",pinyin:["xié"],meaning:"此处不单指邪恶，更指感官引动心念、使人偏离本然的扰动。「九窍之邪」即从窍而入的散乱与偏移。"},{term:"溃",pinyin:["kuì"],meaning:"崩坏、溃散。「奸生于国，时动必溃」——祸乱非凭空而来，总有生处；时机一到，积累的祸患必然爆发。"},{term:"修炼",pinyin:["xiū","liàn"],meaning:"修真炼己。「知之修炼，谓之圣人」——知机是看见，修炼是做到；只知不修不够，只修不知也不够。"}]}),a[7]||(a[7]=n("h3",{id:"中篇-1",tabindex:"-1"},[i("中篇 "),n("a",{class:"header-anchor",href:"#中篇-1","aria-label":'Permalink to "中篇"'},"​")],-1)),e(t,{items:[{term:"盗",pinyin:["dào"],meaning:"非偷窃之盗，而是天地万物之间相互资取、相互消耗的自然关系。「天地，万物之盗」点出这种互取互用的本质。"},{term:"三才",pinyin:["sān","cái"],meaning:"天、地、人。「三盗既宜，三才既安」——天地盗万物、万物盗人、人盗万物，三盗各得其宜则三才安定。"},{term:"百骸理",pinyin:["bǎi","hái","lǐ"],meaning:"身体百骸自然调顺。「食其时，百骸理」——饮食合于时节，身体的各个部分便自然理顺，强调顺时的重要。"},{term:"安",pinyin:["ān"],meaning:"安定、归位。「动其机，万化安」——不是消除变化，而是让变化在得其时机后归于安定。"},{term:"神",pinyin:["shén"],meaning:"「人知其神之神，不知不神之所以神」——世人只见神奇灵妙的一面为神，却不知那看似平常、不显神异的道，才是真正的神妙所在。"},{term:"固躬",pinyin:["gù","gōng"],meaning:"稳固自身。「君子得之固躬」——君子得到盗机之理，能用来稳固自身，不妄动、不轻发。"},{term:"轻命",pinyin:["qīng","mìng"],meaning:"轻忽性命。「小人得之轻命」——同样的盗机之理，小人得之则因贪求而轻忽自身性命，反受其害。"}]}),a[8]||(a[8]=n("h3",{id:"下篇-1",tabindex:"-1"},[i("下篇 "),n("a",{class:"header-anchor",href:"#下篇-1","aria-label":'Permalink to "下篇"'},"​")],-1)),e(t,{items:[{term:"瞽",pinyin:["gǔ"],meaning:"目盲。「瞽者善听」——盲人失去视觉后听觉反而敏锐，喻专注一源则其用倍增，不因缺失而废。"},{term:"绝利一源",pinyin:["jué","lì","yī","yuán"],meaning:"断绝其他利益，专注一个源头。「绝利一源，用师十倍」——精力不分散，聚焦一处，效力可抵十倍。"},{term:"大恩",pinyin:["dà","ēn"],meaning:"「天之无恩而大恩生」——天道看似无情无恩于万物，却以不偏私的方式成就万物，这便是最大的恩。"},{term:"蠢然",pinyin:["chǔn","rán"],meaning:"生动跃动之貌。「迅雷烈风，莫不蠢然」——天地变化虽然猛烈，却自有生机，不是死寂的。"},{term:"余",pinyin:["yú"],meaning:"宽裕、有余。「至乐性余」——真正安乐的人心性宽裕不迫，不因得失而紧绷。"},{term:"廉",pinyin:["lián"],meaning:"简约、不贪。「至静性廉」——真正静定的人心性简约，不被多余的欲望牵走。"},{term:"禽之制",pinyin:["qín","zhī","zhì"],meaning:"擒获、制伏的方法。「禽之制在气」——要制伏外物，关键在把握其气机，而不是硬碰硬的对抗。"},{term:"圣",pinyin:["shèng"],meaning:"「愚人以天地文理圣，我以时物文理哲」——圣在此为通达、不拘泥，不是死守固定文理，而是随时物之变而通达。"},{term:"哲",pinyin:["zhé"],meaning:"明达事理。与「圣」呼应：愚者以固定文理为圣，我则以随时应变、通达事理为明哲。"},{term:"愚",pinyin:["yú"],meaning:"「愚人以天地文理圣」——愚在此是不明变通、拘泥于固定文理，而非单纯的愚蠢。"},{term:"虞圣",pinyin:["yú","shèng"],meaning:"「人以愚虞圣」——以愚昧之心去揣度圣人之境，必然偏差。虞为揣度、测度。"},{term:"奇",pinyin:["qí"],meaning:"「人以奇期圣」——以奇异、非常的标准去期待圣人，反而看不清圣人之道的平常真实。"},{term:"期圣",pinyin:["qī","shèng"],meaning:"期待、衡量圣人之境。「人以奇期圣，我以不奇期圣」——不以奇异标准衡量圣人，才能贴近真实。"},{term:"契",pinyin:["qì"],meaning:"契合、穷尽。「至静之道，律历所不能契」——最深的静定之道，非律历、度数所能完全测度与穷尽。"},{term:"爰",pinyin:["yuán"],meaning:"于是、乃。「爰有奇器，是生万象」——于是有此奇妙的法则（奇器），生出天地万象。"},{term:"奇器",pinyin:["qí","qì"],meaning:"奇妙的法则或器物。「爰有奇器，是生万象，八卦甲子，神机鬼藏」——指八卦、甲子等推演万象的工具与法则。"},{term:"昭昭乎",pinyin:["zhāo","zhāo","hū"],meaning:"明亮清晰的样子。「阴阳相胜之术，昭昭乎进乎象矣」——阴阳制衡推变之法，明白可见地显现于卦象物象之中。"},{term:"进乎象",pinyin:["jìn","hū","xiàng"],meaning:"进入、显现于象（卦象、物象）之中。全经最后一句：至微的道理，终究要落到可见可用的象上，而非悬空。"}]}),a[9]||(a[9]=s('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><blockquote><p>解读仅个人观点，仅供参考，若有疏漏还望海涵，并批评指出</p></blockquote><h3 id="象-这部经在说什么" tabindex="-1">象：这部经在说什么 <a class="header-anchor" href="#象-这部经在说什么" aria-label="Permalink to &quot;象：这部经在说什么&quot;">​</a></h3><p>《阴符经》很短，但语气比《清静经》更峻，也更像一把直接切进事物根处的刀。它关心的不是单纯的安静，而是天地万物如何发动、如何变化、如何互相取用，以及人该怎样看见其中的“机”。</p><p>如果说《清静经》更像从“大道”一路落到“清静工夫”，那么《阴符经》更像在提醒人：天地之间没有死物，一切都在动，一切都有机，一切都在转。</p><h3 id="理-为什么这部经重要" tabindex="-1">理：为什么这部经重要 <a class="header-anchor" href="#理-为什么这部经重要" aria-label="Permalink to &quot;理：为什么这部经重要&quot;">​</a></h3><p>这部经重要，正在于它不温吞。</p><ul><li>它逼人正视变化，而不是沉迷于静态理解</li><li>它逼人正视“机”的存在，而不是只看表面现象</li><li>它逼人承认天地运行自有其理，不会因为人的愿望而改变</li><li>它也提醒人：真正的学习，不只是知道概念，而是学会在变化中见机、守机、应机</li></ul><p>因此，它虽然篇幅极短，却很适合作为理解“道并不只是柔和，也有峻厉一面”的入口。</p><h3 id="用-今天怎么进入这部经" tabindex="-1">用：今天怎么进入这部经 <a class="header-anchor" href="#用-今天怎么进入这部经" aria-label="Permalink to &quot;用：今天怎么进入这部经&quot;">​</a></h3><p>今天读《阴符经》，不必急着把每一句都解释得很满。更好的进入方式，也许是先抓住三个问题：</p><ul><li>我平常看到的是表面，还是能慢慢看见事情发动的“机”？</li><li>我有没有把“自然之道”误解成什么都不做？</li><li>面对变化时，我是在被动卷走，还是能稍微看见它、顺应它、调整自己？</li></ul><p>先抓住这几个问题，再回头读原文，往往会更有力。</p><h2 id="【解读层】分段解读" tabindex="-1">【解读层】分段解读 <a class="header-anchor" href="#【解读层】分段解读" aria-label="Permalink to &quot;【解读层】分段解读&quot;">​</a></h2><h3 id="_1-上篇-天道、人心与发动之机" tabindex="-1">1. 上篇：天道、人心与发动之机 <a class="header-anchor" href="#_1-上篇-天道、人心与发动之机" aria-label="Permalink to &quot;1. 上篇：天道、人心与发动之机&quot;">​</a></h3><p>开篇“观天之道，执天之行，尽矣”很有力量。它先不让人困在繁复名相里，而是直指两件事：看见天道，抓住运行。这里的重点不在偏重“观”还是“执”，而在于先观后执、观执相成。若只有观，容易停在“知道”；若只有执，又容易落成盲动。到了“尽矣”，更像是在说：道理与工夫，至少在这一截已经贯通了。</p><p>“天有五贼，见之者昌。五贼在心，施行于天”也很值得连着读。若只看前一句，容易误解成向外争势；但经文紧接着说“五贼在心”，一下又把人从外争拉回内观。关键不只在看见天地运行中那些会夺势、转势的力量，也在看见人心之中本就有相应之机。</p><p>“天性，人也；人心，机也。立天之道，以定人也”则把重点进一步收到“定”字。前面讲天、讲人、讲心、讲机，关系很多，气机也很活，但一个“定”字下来，整句忽然收住了。它不是宿命地说“人由天定”，而更像是在提醒：正因为人心会动、会偏、会被机牵着走，所以才更需要立住一个更高的准绳，使人不乱、不偏、不失其度。</p><p>到了“天发杀机，移星易宿；地发杀机，龙蛇起陆；人发杀机，天地反覆”，上篇的气势突然推高。“杀机”若只按杀戮来读，会太窄；放回这里，它更像是一种剧烈转变的发动点。真正震人的，尤其是“人发杀机，天地反覆”，因为这提醒人：可怕的不是力量本身，而是不定的力量。一旦人心之机发错，后果可能被极大放大。</p><p>但经文并未停在“可怕”上，而是紧接着说“天人合发，万变定基”。变化并没有消失，关键在于天人与其机能否相合。能合，则万变不只是乱变，最后还会沉到一个新的根基上。</p><p>“性有巧拙，可以伏藏。九窍之邪，在乎三要，可以动静”则又把视线从天地大势收回到人的工夫上。这里的“巧拙”不一定只是高下之分，更像是在承认：人的性分本来就不同，有敏捷处，也有迟钝处。但无论巧拙，都不必急着尽发，所以经文紧接着说“可以伏藏”。</p><p>“九窍之邪”也不必先读成抽象的恶，更像是在说：感官一动，心就容易被牵，人的许多散乱与偏移，确实常常借着这些“窍”而起。关键不在于感官永远不动，而在于能否守住那几个真正重要的关节点，使自己仍有“可以动静”的余地。</p><p>到了“火生于木，祸发必克；奸生于国，时动必溃”，上篇又一次提醒人：祸乱并非凭空而来，它总有生处，也总会在某个时候发动。真正要紧的，不只是看见事情爆发后的样子，而是平时就能看见它从哪里生。</p><p>最后一句“知之修炼，谓之圣人”，则把整段的落点收得很严。这里的“圣”不是空名，也不是后来的称号，而是能从细微处看见端倪，又把所见之理拿来修自己、炼自己的人。若只知而不修，不够；若只修而不知，也不够。知与修，在这里本就是一体的工夫。</p><h3 id="_2-中篇-三盗之理与时机" tabindex="-1">2. 中篇：三盗之理与时机 <a class="header-anchor" href="#_2-中篇-三盗之理与时机" aria-label="Permalink to &quot;2. 中篇：三盗之理与时机&quot;">​</a></h3><p>“天地，万物之盗；万物，人之盗；人，万物之盗”读起来很刺耳，却也因此令人停住。它不是鼓励巧取豪夺，而是在指出：天地之间本就是互相资取、互相成就、互相消耗的关系。</p><p>所以关键不在于有没有“取”，而在于是否得其宜、合其时。经文说“三盗既宜，三才既安”，真正重要的是分寸与时机。</p><h3 id="_3-下篇-反常之言与自然之道" tabindex="-1">3. 下篇：反常之言与自然之道 <a class="header-anchor" href="#_3-下篇-反常之言与自然之道" aria-label="Permalink to &quot;3. 下篇：反常之言与自然之道&quot;">​</a></h3><p>下篇最容易让人一口气读过去，又最值得慢下来。它大量使用反转、对照和近乎悖论式的话语，像是在故意打碎人平常顺手的理解。</p><p>到“自然之道静，故天地万物生。天地之道浸，故阴阳胜。阴阳相推，而变化顺矣”，全篇又忽然落回一个更根本的地方：再繁复的变化，终究没有离开自然之道。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>天地有其自身的运行之理，万物的变化都有发动之机。人若只看表象，常常会错过真正关键的转折点；若能慢慢学着见机、守机、应机，便不会总在变化来临之后才仓促应对。</p><p>《阴符经》提醒人：自然之道并不只是柔和安稳，它也包含肃杀、翻转、制衡与再生。理解这一点，人才不会把“道”误解成空泛的安慰，而会更认真地面对变化本身。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>对我来说，《阴符经》和《清静经》的气质很不一样。</p><p>《清静经》像是在慢慢把人按回心里，让人看见自己为什么会乱、为什么会被牵走；《阴符经》却更像迎面而来的一阵硬风。它不太安慰人，甚至有些句子一上来就会让人不舒服，比如“天地，万物之盗；万物，人之盗；人，万物之盗”。可也正因为这样，它逼着人承认：天地之间本来就不是一张静止温柔的图画，而是流转、取予、消长、推移。</p><p>我现在初读它，最在意的还不是把每一句都讲透，而是它不断提醒我的那个字：机。很多时候，人不是败在事情太难，而是败在根本没看见它什么时候已经开始变了。等到表面上全都显出来，往往已经迟了。</p><p>读到“立天之道，以定人也”时，我最有感觉的是“定”字。前面又是天、又是人、又是心、又是机，很容易越读越散，可一个“定”字下来，整段忽然收了回来。对我来说，这个“定”不是被动地“由天而定”，而更像是人在更大的秩序之下，把自己安住好。事情依然很多，甚至会同时推进，但一旦根稳了，优先级和次第会慢慢自己显出来，这样的人不是没事做了，而是不再被杂事一路拖着乱跑。</p><p>读到“人发杀机，天地反覆”时，我又会被震一下。前面的“移星易宿”“龙蛇起陆”还是天地自然的宏伟之变，可一到“天地反覆”，就会忽然感到人的力量之大。人若不定，力量就会很可怕，甚至会反过来伤到自己。</p><p>再往后读“性有巧拙，可以伏藏。九窍之邪，在乎三要，可以动静”，我更有感觉的反而不是“巧拙”，而是“伏藏”与“动静”。感官会动，欲望会起，就像风来时枝叶摆动，这是自然之理。关键不在于枝叶一点都不能动，而在于根是否还在，干是否还立得住。对我来说，根像是记得自己当下在做什么，干像是主体还在，没有被一阵风整棵吹倒。若根在、干在，即使一时被带动，也不必太懊恼，因为动过之后，仍然可以回来。</p><p>再读“火生于木，祸发必克；奸生于国，时动必溃”，我会想到《易》里的“履霜坚冰至”。很多事情不是到了结果才忽然发生的，而是在很早之前就已经有了生处，有了端倪。若能在“火生于木”时就看见后面的祸，在“奸生于国”时就看见后面的溃，那才是真的知微。</p><p>所以“知之修炼，谓之圣人”这句，我现在更愿意读成：所谓“圣”，未必先是地位，也未必先是后人的封号，而是知微而自修。能看见细微处的势，又能把这个看见反过来修自己，不停在“我懂了”，而是一直做到身上，这样的人才慢慢有了“圣”的意味。</p><p>对现在的我来说，“知”和“修”也越来越不像两件事。就像一边讨论、一边整理、一边完善 Dao，其实也已经是一边在修 Dao、一边在被 Dao 反过来修。若把它们硬分开，反而会失掉它原本活的地方。</p><p>所以这篇我更想慢慢读。它不像《清静经》那样，先给人一个可以安顿下来的地方；它更像先把人叫醒，再问一句：你真的看见了吗？</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《黄帝阴符经》</li><li><a href="https://zh.wikisource.org/wiki/%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93" target="_blank" rel="noreferrer">维基文库：黃帝陰符經</a></li></ul>',46))])}const q=p(d,[["render",g]]);export{x as __pageData,q as default};
